const { Manifold, CrossSection, label } = api;

// ---------------------------------------------------------------
// Royal Crown — a tidy, symmetric regal crown.
//   * clean gold BAND (hollow ring) with rounded rim beads
//   * deep-red velvet INNER band peeking above the rim
//   * an even ring of crown POINTS, each capped with a gold BALL finial
//   * evenly-spaced JEWELS in little gold bezel mounts, alternating
//     ruby / sapphire / emerald / amethyst
// All built with loops on even angular spacing → perfectly symmetric.
// ---------------------------------------------------------------

const GOLD = '#d9a915';
const VELVET = '#7a1228';

// Torus helper via revolve of a circular cross-section.
function torus(majorR, minorR) {
  const circle = CrossSection.circle(minorR, 40).translate([majorR, 0]);
  return Manifold.revolve(circle, 96);
}

const bandOuterR = 9.0;
const bandInnerR = 8.0;
const bandH = 6.0;
const bandTopZ = bandH;

// --- Gold band: hollow ring + rounded beads top & bottom --------
const bandOuter = Manifold.cylinder(bandH, bandOuterR, bandOuterR, 96);
const bandBore = Manifold.cylinder(bandH + 2, bandInnerR, bandInnerR, 96).translate([0, 0, -1]);
const band = bandOuter.subtract(bandBore);

const beadR = (bandOuterR + bandInnerR) / 2;
const rimBeadTop = torus(beadR, 0.7).translate([0, 0, bandTopZ]);
const rimBeadBot = torus(beadR, 0.7).translate([0, 0, 0]);
const goldBand = band.add(rimBeadTop).add(rimBeadBot);

// --- Velvet inner band: a colored shell peeking up above the rim.
const velvetR = bandInnerR + 0.05;
const velvetH = bandH + 1.8;
const velvetOuter = Manifold.cylinder(velvetH, velvetR, velvetR, 96);
const velvetBore = Manifold.cylinder(velvetH + 2, velvetR - 0.9, velvetR - 0.9, 96).translate([0, 0, -1]);
const velvet = label(velvetOuter.subtract(velvetBore), 'velvet', { color: VELVET });

// --- Crown points: even ring, tapered spike + gold ball finial.
const numPoints = 8;
const pointRadius = beadR;
const pointBaseR = 1.7;
const pointH = 9.0;
const finialR = 1.25;

const goldFeatures = [goldBand];

for (let i = 0; i < numPoints; i++) {
  const a = (i * 2 * Math.PI) / numPoints;
  const px = pointRadius * Math.cos(a);
  const py = pointRadius * Math.sin(a);

  const spike = Manifold.cylinder(pointH, pointBaseR, 0.25, 48)
    .translate([px, py, bandTopZ - 0.5]);
  const finial = Manifold.sphere(finialR, 32)
    .translate([px, py, bandTopZ - 0.5 + pointH]);

  goldFeatures.push(spike, finial);
}

// --- Jewels in gold bezel mounts around the band ---------------
const numJewels = 8;
const jewelZ = bandH * 0.5;
const jewelSeatR = bandOuterR - 0.3;
const bezelR = 1.85;
const bezelDepth = 1.5;
const jewelR = 1.6;

const jewelColors = [
  { name: 'ruby', color: '#d61f3a' },
  { name: 'sapphire', color: '#1f5fd6' },
  { name: 'emerald', color: '#1ea85a' },
  { name: 'amethyst', color: '#8a35c9' },
];

const jewelGroups = {}; // name -> { color, shapes[] }

for (let i = 0; i < numJewels; i++) {
  // Offset so each jewel sits between two crown points.
  const a = (i * 2 * Math.PI) / numJewels + Math.PI / numJewels;
  const dx = Math.cos(a), dy = Math.sin(a);
  const bx = jewelSeatR * dx, by = jewelSeatR * dy;

  // Bezel: a short gold cylinder poking radially out of the band.
  const bezel = Manifold.cylinder(bezelDepth + 0.8, bezelR, bezelR * 0.9, 36)
    .rotate([90, 0, 0])                          // axis -> +Y
    .rotate([0, 0, (a * 180) / Math.PI - 90])    // aim radially outward
    .translate([bx - dx * 0.9, by - dy * 0.9, jewelZ]);
  goldFeatures.push(bezel);

  // Jewel sphere nestled proud of the bezel.
  const jx = (jewelSeatR + bezelDepth - 0.4) * dx;
  const jy = (jewelSeatR + bezelDepth - 0.4) * dy;
  const jewel = Manifold.sphere(jewelR, 32).translate([jx, jy, jewelZ]);

  const c = jewelColors[i % jewelColors.length];
  (jewelGroups[c.name] ??= { color: c.color, shapes: [] }).shapes.push(jewel);
}

// --- Assemble ---------------------------------------------------
const gold = label(Manifold.union(goldFeatures), 'gold', { color: GOLD });

let model = gold.add(velvet);
for (const [name, grp] of Object.entries(jewelGroups)) {
  const jewelSolid = label(Manifold.union(grp.shapes), name, { color: grp.color });
  model = model.add(jewelSolid);
}

return model;
